28	cudaError_t BatchDecodeWithPagedKVCacheDispatched(Params params, typename Params::DTypeO* tmp_v,
29	                                                  float* tmp_s, bool enable_pdl,
30	                                                  cudaStream_t stream);
31	
32	}  // namespace flashinfer
