338	/*!
339	 * \brief Partition Paged KV-Cache into multiple chunks on KV sequence length
340	 * \tparam IdType A template type indicates the index data type
341	 * \param old_batch_size The batch size of the old Paged KV-Cache
342	 * \param old_page_indptr_h The host-side page indptr of the old Paged KV-Cache
343	 * \param max_num_pages_per_batch The maximum number of pages per batch
344	 * \param new_paged_kv_d The device-side new Paged KV-Cache
345	 * \param stream The cuda stream to launch the kernel
346	 * \return status Indicates whether CUDA calls are successful
347	 */
348	template <typename IdType>
349	inline auto DecodeSplitKVIndptr(IdType* indptr_h, uint32_t batch_size, uint32_t kv_chunk_size) {
350	  std::vector<IdType> request_indices, kv_tile_indices, o_indptr;
351	  o_indptr.push_back(0);
352	
353	  for (uint32_t batch_idx = 0; batch_idx < batch_size; batch_idx++) {
354	    uint32_t num_chunks_kv = ceil_div(
355	        std::max<uint32_t>(indptr_h[batch_idx + 1] - indptr_h[batch_idx], 1U), kv_chunk_size);
356	    for (uint32_t kv_tile_idx = 0; kv_tile_idx < num_chunks_kv; ++kv_tile_idx) {
357	      request_indices.push_back(batch_idx);
358	      kv_tile_indices.push_back(kv_tile_idx);
359	    }
360	    o_indptr.push_back(o_indptr.back() + num_chunks_kv);
361	  }
362	
363	  return std::make_tuple(request_indices, kv_tile_indices, o_indptr);
364	}

